const stats = $input.first().json;

return [{
  json: {
    orders: {
      total: parseInt(stats.total_orders) || 0,
      new: parseInt(stats.new_orders) || 0,
      processing: parseInt(stats.processing_orders) || 0,
      shipped: parseInt(stats.shipped_orders) || 0,
      delivered: parseInt(stats.delivered_orders) || 0,
      returned: parseInt(stats.returned_orders) || 0
    },
    products: {
      total: parseInt(stats.total_products) || 0
    },
    returns: {
      total: parseInt(stats.total_returns) || 0
    },
    revenue: {
      total: parseFloat(stats.total_revenue) || 0
    }
  }
}];
